from zeep import Client

def lookup_policy(policy_number, customer_name):
    client = Client('http://insurancecompany.com/soap/endPoint?wsdl')
    
    request_data = {
        'policyNumber': policy_number,
        'customerName': customer_name
    }

    response = client.service.InsurancePolicy(request_data)
    return response

